# ==========================================
# 5. REST API ROUTES & FLASK LOGIC
# ==========================================

def _get_state():
    """Safely fetch SystemState row; returns None on any DB error."""
    try:
        return SystemState.query.first()
    except Exception:
        return None

@app.before_request
def check_admin_session():
    # ── Single-session model ──────────────────────────────────────────────────
    # Only the most-recently-authenticated device holds a valid session.
    # When another device takes over, the old device's admin_id no longer
    # matches state.active_session_id → 403 → client redirects to login.

    # Guard admin API routes — must have a valid, current admin session
    if request.path.startswith('/api/admin'):
        if not session.get('is_admin') or not session.get('admin_id'):
            return jsonify({"error": "Unauthorized"}), 403
        # Validate that this device still holds the active session
        try:
            state = _get_state()
            if state and state.active_session_id and session['admin_id'] != state.active_session_id:
                session.pop('is_admin', None)
                session.pop('admin_id', None)
                return jsonify({"error": "Session taken over"}), 403
        except Exception:
            pass

    # Guard /admin page — unauthenticated or displaced browsers go to login
    if request.path == '/admin' and request.method == 'GET':
        if not session.get('is_admin'):
            return redirect(url_for('admin_login'))
        # Also kick displaced admin browsers back to login
        try:
            state = _get_state()
            if state and state.active_session_id and session.get('admin_id') != state.active_session_id:
                session.pop('is_admin', None)
                session.pop('admin_id', None)
                return redirect(url_for('admin_login'))
        except Exception:
            pass

    # Guard employee API routes — must have a valid, current employee session
    if request.path.startswith('/api/employee') or request.path.startswith('/api/orders') or request.path.startswith('/api/stream') or request.path == '/api/employee/stream':
        if not session.get('is_employee') and not session.get('is_admin'):
            return jsonify({"error": "Unauthorized"}), 403
        if session.get('is_employee') and not session.get('is_admin'):
            try:
                state = _get_state()
                if state and state.active_employee_session_id and session.get('employee_id') != state.active_employee_session_id:
                    session.pop('is_employee', None)
                    session.pop('employee_id', None)
                    return jsonify({"error": "Session taken over"}), 403
            except Exception:
                pass


@app.route('/api/inventory/<int:ing_id>', methods=['DELETE'])
def delete_ingredient(ing_id):
    if not session.get('is_admin'):
        return jsonify({"error": "Unauthorized"}), 403
    ing = Ingredient.query.get(ing_id)
    if not ing:
        return jsonify({"error": "Not found"}), 404
    name = ing.name
    RecipeItem.query.filter_by(ingredient_id=ing_id).delete()
    db.session.delete(ing)
    db.session.commit()
    push_employee_event('stock_update', {})
    log_audit("Inventory: Ingredient Deleted", f"Admin deleted ingredient: {name}")
    return jsonify({"ok": True})


@app.route('/')
def storefront():
    token = request.args.get('token')

    # ── Closed / Not Configured pages ───────────────────────────────────
    def closed_page(title, icon, headline, sub, extra=''):
        # icon param kept for compatibility but logo image is always used
        return f"""<!DOCTYPE html><html><head>
        <meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1">
        <link rel="icon" type="image/jpeg" href="/static/images/9599.jpg">
        <link rel="stylesheet" href="https://use.fontawesome.com/releases/v6.4.0/css/all.css" crossorigin="anonymous">
        <link href="https://fonts.googleapis.com/css2?family=Playfair+Display:wght@700;900&family=DM+Sans:wght@400;600;700&display=swap" rel="stylesheet">
        <title>{title} | 9599 Tea & Coffee</title>
        <style>
            *{{box-sizing:border-box;margin:0;padding:0;}}
            body{{font-family:'DM Sans',sans-serif;background:#F5EFE6;display:flex;align-items:center;justify-content:center;min-height:100vh;padding:20px;}}
            .card{{background:white;border-radius:20px;padding:50px 40px;max-width:440px;width:100%;text-align:center;box-shadow:0 20px 50px rgba(0,0,0,0.08);border:1px solid #EFEBE4;}}
            .logo-wrap{{margin-bottom:20px;}}
            .logo-wrap img{{width:90px;height:90px;border-radius:50%;object-fit:cover;border:3px solid #D7CCC8;box-shadow:0 4px 16px rgba(111,78,55,0.15);}}
            .logo-wrap .logo-fallback{{width:90px;height:90px;border-radius:50%;background:#F5EFE6;border:3px solid #D7CCC8;display:inline-flex;align-items:center;justify-content:center;font-size:2.8rem;}}
            h2{{font-family:'Playfair Display',serif;font-size:1.8rem;color:#3E2723;margin-bottom:12px;}}
            p{{color:#8D6E63;font-size:0.95rem;line-height:1.6;}}
            .badge{{display:inline-block;background:#F5EFE6;color:#6F4E37;font-weight:700;font-size:0.85rem;padding:8px 18px;border-radius:50px;margin-top:18px;border:1px solid #D7CCC8;}}
        </style></head><body>
        <div class="card">
            <div class="logo-wrap">
                <img src="/static/images/9599.jpg" alt="9599 Tea &amp; Coffee"
                     onerror="this.style.display='none';this.nextElementSibling.style.display='inline-flex';">
                <span class="logo-fallback" style="display:none;">☕</span>
            </div>
            <h2>{headline}</h2>
            <p>{sub}</p>
            {extra}
        </div></body></html>"""

    # ── Validate token (permanent — just proves it's the real shop link) ─
    if not token:
        return closed_page(
            "Not Found", "🔒",
            "Store Link Required",
            "Please use the official ordering link provided by 9599 Tea & Coffee."
        ), 403

    try:
        token_serializer.loads(token, max_age=None)   # no expiry — permanent link
    except BadSignature:
        return closed_page(
            "Invalid Link", "⚠️",
            "Invalid Link",
            "This ordering link is not valid. Please get the correct link from the shop."
        ), 403
    except Exception:
        pass   # SignatureExpired not raised when max_age=None

    # ── Check schedule ───────────────────────────────────────────────────
    status = get_store_status()

    # ── Check if today is a manually marked closed day ───────────────────
    today_str = get_ph_time().strftime('%Y-%m-%d')
    if ClosedDay.query.filter_by(date_str=today_str).first():
        day_names = ['Monday','Tuesday','Wednesday','Thursday','Friday','Saturday','Sunday']
        next_open = None
        for delta in range(1, 15):
            check = get_ph_time() + timedelta(days=delta)
            check_str = check.strftime('%Y-%m-%d')
            if not ClosedDay.query.filter_by(date_str=check_str).first():
                next_open = day_names[check.weekday()] + ' at ' + status['open_time']
                break
        return closed_page(
            "Closed Today", "🧋",
            "We're Closed Today",
            "9599 Tea &amp; Coffee is taking a day off. We'll be back soon!",
            f'<div class="badge">Next opening: {next_open or status["next_open"]}</div>'
        ), 403

    if status["closing_soon"]:
        return closed_page(
            "Closing Soon", "🕐",
            "We're Closing Soon!",
            f"Online ordering closes <b>1 hour before closing time</b> to ensure your order can be prepared.<br><br>"
            f"Today's hours: <b>{status['open_time']} – {status['close_time']}</b><br>"
            f"Last order accepted at: <b>{status['cutoff_time']}</b>",
            f'<div class="badge">Next opening: {status["next_open"]}</div>'
        ), 403

    if not status["open"]:
        return closed_page(
            "Closed", "🧋",
            "We're Currently Closed",
            f"9599 Tea & Coffee is not accepting orders right now.<br><br>"
            f"<b>Today's Hours:</b> {status['open_time']} – {status['close_time']}<br><br>"
            f"Online orders close 1 hour before closing time.",
            f'<div class="badge">Next opening: {status["next_open"]}</div>'
        ), 403

    # ── Store is open — serve the storefront ─────────────────────────────
    return render_template_string(
        STOREFRONT_HTML,
        open_time=status["open_time"],
        close_time=status["cutoff_time"],   # cutoff = 1h before actual close
        actual_close_time=status["close_time"],
        google_client_id=GOOGLE_CLIENT_ID
    )

@app.route('/api/auth/google', methods=['POST'])
def google_auth():
    data = request.json
    token = data.get('token')
    if not token: return jsonify({"error": "No token provided"}), 400
    try:
        verify_url = f"https://oauth2.googleapis.com/tokeninfo?id_token={token}"
        response = requests.get(verify_url)
        if response.status_code == 200:
            user_info = response.json()
            session['customer_verified'] = True
            session['customer_name'] = user_info.get('name', 'Valued Patron')
            session['customer_email'] = user_info.get('email', 'google_user@local')
            return jsonify({"status": "success"})
        return jsonify({"error": "Invalid Google Token"}), 401
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route('/api/auth/manual', methods=['POST'])
@limiter.limit("30 per minute")
def manual_auth():
    """Manual sign-in: name + email + optional phone + required location. No Google OAuth required."""
    data = request.json or {}
    name  = (data.get('name') or '').strip()
    email = (data.get('email') or '').strip()
    phone = (data.get('phone') or '').strip()
    lat   = (data.get('lat') or '').strip()
    lng   = (data.get('lng') or '').strip()
    address = (data.get('address') or '').strip()
    if not name:
        return jsonify({"error": "Full name is required."}), 400
    if not email or '@' not in email:
        return jsonify({"error": "A valid email address is required."}), 400
    if not lat or not lng:
        return jsonify({"error": "Location is required. Please use 'Use My Current Location'."}), 400
    # Require email verification before granting access
    verified_email = session.get('email_verified_for', '').strip().lower()
    if verified_email != email.lower():
        return jsonify({"error": "Please verify your email first. Click 'Verify Your Email' and check your inbox."}), 403

    session['customer_verified'] = True
    session['customer_name']     = name
    session['customer_email']    = email
    session['customer_phone']    = phone
    session['customer_lat']      = lat
    session['customer_lng']      = lng
    session['customer_address']  = address
    return jsonify({"status": "success"})


@app.route('/api/auth/send_email_verification', methods=['POST'])
@limiter.limit("5 per minute")
def send_email_verification():
    """Send a verification link to the customer's Gmail before they can place orders."""
    data  = request.json or {}
    email = (data.get('email') or '').strip()
    if not email or '@' not in email:
        return jsonify({"error": "A valid email address is required."}), 400

    # Generate a signed token valid for 15 minutes
    token = token_serializer.dumps(email.lower(), salt='email-verify-2024')

    # Build the verification URL
    base_url = (os.environ.get('APP_BASE_URL') or request.host_url).rstrip('/')
    verify_url = f"{base_url}/verify-email/{token}"

    ok, err = send_verification_email(email, verify_url)
    if not ok:
        return jsonify({"error": f"Could not send email: {err}"}), 500

    # Store pending email in session so we can validate the token later
    session['pending_verify_email'] = email.lower()
    return jsonify({"status": "sent", "message": "Verification email sent! Check your Gmail inbox."})


