# ══════════════════════════════════════════════════════════════════════════════
# PHONE OTP — SEND & VERIFY ROUTES
# ══════════════════════════════════════════════════════════════════════════════

@app.route('/api/otp/send', methods=['POST'])
@limiter.limit("3 per 10 minutes")
def otp_send():
    """
    Request a 6-digit OTP for the given phone number.
    Rate-limited to 3 requests per 10 minutes to prevent SMS-bombing.
    """
    data  = request.get_json(silent=True) or {}
    phone = (data.get('phone') or '').strip()

    if not phone or not re.fullmatch(r'[\d\s\+\-\(\)]{7,20}', phone):
        return jsonify({"status": "error", "message": "Invalid phone number. Please enter a valid PH mobile number."}), 400

    # Invalidate any previous unverified OTP for this number
    try:
        PhoneOTP.query.filter_by(phone=phone, verified=False).delete()
        db.session.commit()
    except Exception:
        db.session.rollback()

    code = str(random.randint(100000, 999999))
    otp  = PhoneOTP(phone=phone, code=code)
    db.session.add(otp)
    try:
        db.session.commit()
    except Exception as e:
        db.session.rollback()
        return jsonify({"status": "error", "message": "Could not save OTP. Please try again."}), 500

    ok, err = send_otp_sms(phone, code)
    if not ok:
        # Remove the saved OTP if SMS delivery failed
        try:
            db.session.delete(otp)
            db.session.commit()
        except Exception:
            db.session.rollback()
        return jsonify({"status": "error", "message": err or "Failed to send SMS. Please try again."}), 502

    # Clear any previous session verification so the customer must re-verify
    session.pop('otp_verified_phone', None)
    return jsonify({"status": "sent", "message": f"A 6-digit code was sent to {phone}. It expires in 5 minutes."})


@app.route('/api/otp/verify', methods=['POST'])
@limiter.limit("10 per 10 minutes")
def otp_verify():
    """
    Verify the OTP code entered by the customer.
    On success, stores the verified phone in the server-side session.
    """
    data  = request.get_json(silent=True) or {}
    phone = (data.get('phone') or '').strip()
    code  = (data.get('code')  or '').strip()

    if not phone or not code:
        return jsonify({"status": "error", "message": "Phone and code are both required."}), 400

    # Always fetch the most recent unverified OTP for this number
    otp = (PhoneOTP.query
           .filter_by(phone=phone, verified=False)
           .order_by(PhoneOTP.created_at.desc())
           .first())

    if not otp:
        return jsonify({"status": "error", "message": "No active OTP found. Please request a new code."}), 400

    if otp.is_expired():
        try:
            db.session.delete(otp)
            db.session.commit()
        except Exception:
            db.session.rollback()
        return jsonify({"status": "error", "message": "Code has expired. Please request a new one."}), 400

    if otp.attempts >= 5:
        try:
            db.session.delete(otp)
            db.session.commit()
        except Exception:
            db.session.rollback()
        return jsonify({"status": "error", "message": "Too many wrong attempts. Please request a new code."}), 429

    if otp.code != code:
        otp.attempts += 1
        try:
            db.session.commit()
        except Exception:
            db.session.rollback()
        remaining = max(0, 5 - otp.attempts)
        return jsonify({"status": "error", "message": f"Incorrect code. {remaining} attempt(s) remaining."}), 400

    # ✅ Code is correct — mark as verified and store in session
    otp.verified = True
    try:
        db.session.commit()
    except Exception:
        db.session.rollback()

    session['otp_verified_phone'] = phone
    log_audit("Phone OTP Verified", f"Phone {phone} verified successfully")
    return jsonify({"status": "verified", "message": "Phone number verified! You may now place your order."})



@app.route('/reserve', methods=['POST'])
@limiter.limit("5 per minute")
def reserve_blend():
    data = request.json
    email  = data.get('email', '')
    phone  = data.get('phone', '')
    name   = data.get('name', '')
    total  = float(data.get('total', 0))

    # ── OTP gate: phone must have been verified this session ──────────────────
    verified_phone = session.get('otp_verified_phone', '')
    if not verified_phone:
        return jsonify({
            "status": "otp_required",
            "message": "Please verify your phone number before placing an order."
        }), 403
    # Normalize both numbers and compare so formatting differences don't block
    if _normalize_ph_number(verified_phone) != _normalize_ph_number(phone):
        return jsonify({
            "status": "otp_required",
            "message": "Verified phone does not match. Please re-verify your current phone number."
        }), 403
    # ─────────────────────────────────────────────────────────────────────────

    # ── Behavioral limit gate ─────────────────────────────────────────────
    allowed, err_msg, flags = check_order_limits(email, phone, name, total)
    if not allowed:
        return jsonify({"status": "blocked", "message": err_msg}), 429
    # ─────────────────────────────────────────────────────────────────────

    # ── Duplicate order check ─────────────────────────────────────────────
    norm_email = (email or '').lower().strip()
    dup_window = get_ph_time() - timedelta(hours=2)
    # Block if same email placed any order in the last 2 hours
    if norm_email:
        recent_by_email = Reservation.query.filter(
            Reservation.patron_email == norm_email,
            Reservation.created_at >= dup_window,
            Reservation.order_source == 'Online'
        ).first()
        if recent_by_email:
            return jsonify({
                "status": "blocked",
                "message": "This email was already used to place a recent order. Please wait before ordering again."
            }), 429
    # Block if identical item names are submitted again within 2 hours (any email)
    incoming_items = data.get('items', [])
    incoming_names = sorted([str(i.get('foundation','')).strip().lower() for i in incoming_items])
    if incoming_names:
        recent_orders = Reservation.query.filter(
            Reservation.created_at >= dup_window,
            Reservation.order_source == 'Online'
        ).all()
        for ro in recent_orders:
            ro_names = sorted([inf.foundation.strip().lower() for inf in ro.infusions])
            if ro_names == incoming_names:
                return jsonify({
                    "status": "blocked",
                    "message": "This exact order was already placed recently. Please try a different combination."
                }), 429
    # ─────────────────────────────────────────────────────────────────────

    try:
        initial_status = "Waiting Confirmation"
        # Large orders need staff confirmation before they can be Prepared
        if 'large_order' in flags:
            initial_status = "Pending Staff Approval"

        new_res = Reservation(
            patron_name=name,
            patron_email=email,
            patron_phone=phone,
            total_investment=total,
            pickup_time=data['pickup_time'],
            order_source="Online",
            status=initial_status,
            patron_address=data.get('address',''),
            is_paid=True,  # GCash online payment — auto-marked as paid
            user_agent=request.headers.get('User-Agent','')[:300],
            ip_address=get_client_ip()
        )
        db.session.add(new_res)
        db.session.flush()
        for i in data['items']:
            new_inf = Infusion(
                reservation_id=new_res.id,
                foundation=i['foundation'],
                sweetener=i.get('sweetener','Standard'),
                ice_level=i.get('ice','Normal'),
                pearls=i.get('pearls','Take-Out'),
                cup_size=i.get('size','16 oz'),
                addons=i.get('addons',''),
                item_total=i['price']
            )
            db.session.add(new_inf)

        # ── Create OrderMeta & update reputation ──────────────────────────
        meta = build_order_meta(new_res.id, flags, total, email)

        db.session.commit()

        push_event('order_new', {
            'code': new_res.reservation_code,
            'name': name,
            'total': total,
            'flags': flags
        })

        # Log suspicious patterns for audit trail
        if 'suspicious_pattern' in flags:
            log_audit("Suspicious Pattern Detected", f"Order {new_res.reservation_code}: {name} ordered 5+ times in 1 hour")
        if 'large_order' in flags:
            log_audit("Large Order — Staff Approval Required",
                      f"Order {new_res.reservation_code}: ₱{total:.2f} — needs staff confirmation before prep")

        resp = {
            "status": "success",
            "reservation_code": new_res.reservation_code,
            "flags": flags,
        }
        if 'large_order' in flags:
            resp["prepayment_amount"] = meta.prepayment_amount
            resp["message"] = (
                f"Your order has been received and is pending staff approval "
                f"(large order ≥ ₱{LARGE_ORDER_THRESHOLD:.0f}). "
                f"A holding fee of ₱{meta.prepayment_amount:.2f} may be collected on pickup."
            )
        return jsonify(resp), 201
    except Exception as e:
        db.session.rollback()
        return jsonify({"status": "error", "message": str(e)}), 500

@app.route('/api/permission_request', methods=['POST'])
def permission_request():
    try:
        data = request.get_json(force=True, silent=True) or {}
        code = data.get('code', '').strip()
        name = (data.get('name') or 'Unknown').strip()
        address = data.get('address', '').strip()
        message = data.get('message', '').strip()
        if not code:
            return jsonify({"status": "error", "message": "Missing request code"}), 400
        existing = PermissionRequest.query.filter_by(request_code=code).first()
        if not existing:
            pr = PermissionRequest(request_code=code, customer_name=name, address=address, message=message, granted=False)
            db.session.add(pr)
            db.session.commit()
        return jsonify({"status": "ok"})
    except Exception as e:
        db.session.rollback()
        return jsonify({"status": "error", "message": str(e)}), 500

@app.route('/api/permission_status')
def permission_status():
    code = request.args.get('code', '')
    pr = PermissionRequest.query.filter_by(request_code=code).first()
    if pr:
        return jsonify({"granted": pr.granted, "reply_message": pr.employee_reply or ''})
    return jsonify({"granted": False, "reply_message": ''})

