@app.route('/api/orders')
def api_orders():
    if not session.get('is_admin') and not session.get('is_employee'): return jsonify({"status": "error"}), 403
    try:
        res = Reservation.query.filter(Reservation.order_source != 'Legacy Notebook').order_by(Reservation.created_at.desc()).limit(50).all()
        def _fmt_order(r):
            try:
                meta = OrderMeta.query.filter_by(reservation_id=r.id).first()
            except Exception:
                meta = None
            # Safely read is_paid: fall back to order_source check if column missing
            try:
                is_paid_val = r.is_paid
            except Exception:
                is_paid_val = (r.order_source == 'Online')
            return {
                'id': r.id,
                'code': r.reservation_code,
                'source': r.order_source or '',
                'name': r.patron_name or '',
                'email': r.patron_email or '',
                'phone': r.patron_phone if r.patron_phone is not None else '',
                'address': r.patron_address if r.patron_address is not None else '',
                'process_type': r.order_source or '',
                'total': r.total_investment or 0.0,
                'status': r.status or '',
                'pickup_time': r.pickup_time or '',
                'created_at': r.created_at.strftime('%Y-%m-%d %H:%M:%S') if r.created_at else None,
                'over_limit': len(r.infusions) >= 2,
                'items': [{'foundation': i.foundation, 'size': i.cup_size, 'addons': i.addons, 'sweetener': i.sweetener, 'ice': i.ice_level, 'item_total': i.item_total or 0.0} for i in r.infusions],
                # ── fraud control metadata ──
                'is_flagged':               meta.is_flagged if meta else False,
                'flag_reason':              meta.flag_reason if meta else '',
                'requires_staff_confirm':   meta.requires_staff_confirmation if meta else False,
                'staff_confirmed':          meta.staff_confirmed if meta else True,
                'prepayment_required':      meta.prepayment_required if meta else False,
                'prepayment_amount':        meta.prepayment_amount if meta else 0.0,
                'prepayment_collected':     meta.prepayment_collected if meta else False,
                'is_paid':                  is_paid_val,
                'has_pickup_photo':         meta.has_pickup_photo if meta else False,
            }
        orders_list = []
        for r in res:
            try:
                orders_list.append(_fmt_order(r))
            except Exception as row_err:
                print(f"api_orders: skipping order id={r.id} due to error: {row_err}")
        return jsonify({'orders': orders_list})
    except Exception as e:
        print(f"api_orders error: {e}")
        return jsonify({"status": "error", "message": str(e)}), 500

@app.route('/api/admin/manual_order', methods=['POST'])
def admin_manual_order():
    if not session.get('is_admin') and not session.get('is_employee'): return jsonify({"error": "Unauthorized"}), 403

    # ── Store hours guard for walk-in POS ────────────────────────────────
    # Employees may place walk-in orders from open_time up to actual close_time
    # (unlike the online storefront which cuts off 1 hour early).
    now = get_ph_time()
    today_str = now.strftime('%Y-%m-%d')
    if ClosedDay.query.filter_by(date_str=today_str).first():
        return jsonify({"error": "The store is marked closed today. No walk-in orders can be placed."}), 403
    dow = now.weekday()
    oh, om, ch, cm = get_schedule_for_day(dow)
    def _fmt(h, m):
        suffix = 'AM' if h < 12 else 'PM'
        return f"{h % 12 or 12}:{m:02d} {suffix}"
    open_dt  = now.replace(hour=oh, minute=om, second=0, microsecond=0)
    close_dt = now.replace(hour=ch, minute=cm, second=0, microsecond=0)
    if not (open_dt <= now < close_dt):
        return jsonify({
            "error": f"Walk-in orders are only accepted during store hours "
                     f"({_fmt(oh, om)} – {_fmt(ch, cm)}). The store is currently closed."
        }), 403
    # ── End store hours guard ────────────────────────────────────────────

    data = request.json
    customer_name = data.get('customer_name', 'Walk-In')
    try:
        res = Reservation(patron_name=customer_name, patron_email="walkin@local", total_investment=data['total'], pickup_time="Walk-In", status="Waiting Confirmation", order_source="Manual/Walk-In", patron_address="Walk-In")
        db.session.add(res)
        db.session.flush()
        for i in data['items']:
            inf = Infusion(reservation_id=res.id, foundation=i['foundation'], cup_size=i.get('size','16 oz'), sweetener=i.get('sugar','N/A'), ice_level=i.get('ice','N/A'), pearls='Walk-In', addons=i.get('addons',''), item_total=i['price'])
            db.session.add(inf)
        db.session.commit()
        push_event('order_new', {'code': res.reservation_code, 'name': customer_name, 'total': data['total']})
        return jsonify({"status": "success", "reservation_code": res.reservation_code})
    except Exception as e:
        db.session.rollback()
        return jsonify({"status": "error", "message": str(e)}), 500

@app.route('/api/finance/daily', methods=['GET'])
def daily_finance():
    if not session.get('is_admin'): return jsonify({"error": "Unauthorized"}), 403
    try:
        now = get_ph_time()
        s = now.replace(hour=0, minute=0, second=0, microsecond=0)
        e = now.replace(hour=23, minute=59, second=59, microsecond=999999)
        ords = Reservation.query.filter(Reservation.created_at >= s, Reservation.created_at <= e).all()
        exps = Expense.query.filter(Expense.created_at >= s, Expense.created_at <= e).all()
        return jsonify({
            "system_total": round(sum(o.total_investment or 0.0 for o in ords), 2),
            "expenses_total": round(sum(x.amount or 0.0 for x in exps), 2),
            "expenses": [{"desc": x.description, "amount": x.amount or 0.0} for x in exps]
        })
    except Exception as e:
        print(f"daily_finance error: {e}")
        return jsonify({"error": str(e), "system_total": 0, "expenses_total": 0, "expenses": []}), 500

@app.route('/api/finance/report', methods=['GET'])
def finance_report():
    if not session.get('is_admin'): return jsonify({"error": "Unauthorized"}), 403
    try:
        mode = request.args.get('mode', 'weekly')
        days = 30 if mode == 'monthly' else 7
        now = get_ph_time()
        result = []
        for i in range(days - 1, -1, -1):
            day = now - timedelta(days=i)
            s = day.replace(hour=0, minute=0, second=0, microsecond=0)
            e = day.replace(hour=23, minute=59, second=59, microsecond=999999)
            ords = Reservation.query.filter(Reservation.created_at >= s, Reservation.created_at <= e).all()
            exps = Expense.query.filter(Expense.created_at >= s, Expense.created_at <= e).all()
            revenue = sum(o.total_investment or 0.0 for o in ords)
            expenses = sum(x.amount or 0.0 for x in exps)
            result.append({
                "date": day.strftime('%b %d'),
                "revenue": round(revenue, 2),
                "expenses": round(expenses, 2),
                "profit": round(revenue - expenses, 2),
                "orders": len(ords)
            })
        return jsonify(result)
    except Exception as e:
        print(f"finance_report error: {e}")
        return jsonify({"error": str(e)}), 500

@app.route('/api/finance/bestsellers', methods=['GET'])
def finance_bestsellers():
    if not session.get('is_admin'): return jsonify({"error": "Unauthorized"}), 403
    mode = request.args.get('mode', 'all')
    now = get_ph_time()
    if mode == 'today':
        start = now.replace(hour=0, minute=0, second=0, microsecond=0)
        infusions = Infusion.query.join(Reservation).filter(Reservation.created_at >= start).all()
    elif mode == 'week':
        start = now - timedelta(days=7)
        infusions = Infusion.query.join(Reservation).filter(Reservation.created_at >= start).all()
    else:
        infusions = Infusion.query.all()
    counts = {}
    for inf in infusions:
        counts[inf.foundation] = counts.get(inf.foundation, 0) + 1
    top = sorted(counts.items(), key=lambda x: x[1], reverse=True)[:10]
    return jsonify([{"name": k, "count": v} for k, v in top])

@app.route('/api/finance/low_stock', methods=['GET'])
def finance_low_stock():
    if not session.get('is_admin') and not session.get('is_employee'): return jsonify({"error": "Unauthorized"}), 403
    ings = Ingredient.query.order_by(Ingredient.stock).all()
    result = []
    for ing in ings:
        if ing.unit == 'pcs':
            threshold = 50
        elif ing.unit in ('ml', 'grams', 'g'):
            threshold = 500
        else:
            threshold = 200
        pct = (ing.stock / max(threshold * 4, 1)) * 100
        if ing.stock <= 0:
            level = 'critical'
        elif ing.stock <= threshold:
            level = 'low'
        elif pct <= 50:
            level = 'medium'
        else:
            continue
        result.append({"name": ing.name, "stock": ing.stock, "unit": ing.unit, "level": level, "threshold": threshold})
    return jsonify(result)

@app.route('/api/orders/history', methods=['GET'])
def order_history():
    if not session.get('is_admin'): return jsonify({"error": "Unauthorized"}), 403
    try:
        q = request.args.get('q', '').strip()
        status_filter = request.args.get('status', '')
        page = max(1, int(request.args.get('page', 1)))
        per_page = 20
        query = Reservation.query
        if q:
            query = query.filter(db.or_(
                Reservation.patron_name.ilike(f'%{q}%'),
                Reservation.reservation_code.ilike(f'%{q}%')
            ))
        if status_filter:
            query = query.filter(Reservation.status == status_filter)
        total = query.count()
        orders = query.order_by(Reservation.created_at.desc()).offset((page - 1) * per_page).limit(per_page).all()
        def _safe_row(o):
            try:
                is_paid_val = o.is_paid
            except Exception:
                is_paid_val = (o.order_source == "Online")
            return {
                "id": o.id, "code": o.reservation_code, "name": o.patron_name or '',
                "total": o.total_investment or 0.0, "status": o.status or '', "source": o.order_source or '',
                "pickup": o.pickup_time or '',
                "address": o.patron_address if o.patron_address is not None else '',
                "date": o.created_at.strftime('%b %d, %Y') if o.created_at else '',
                "time": o.created_at.strftime('%I:%M %p') if o.created_at else '',
                "items": [i.foundation for i in o.infusions],
                "is_paid": is_paid_val
            }
        return jsonify({
            "total": total, "page": page, "per_page": per_page,
            "orders": [_safe_row(o) for o in orders]
        })
    except Exception as e:
        print(f"order_history error: {e}")
        return jsonify({"error": str(e), "total": 0, "page": 1, "per_page": 20, "orders": []}), 500

