# ── ADMIN ANALYTICS: SALES TRENDS ─────────────────────────────

@app.route('/api/admin/analytics/sales_trend', methods=['GET'])
def analytics_sales_trend():
    if not session.get('is_admin'):
        return jsonify({"error": "Unauthorized"}), 403
    try:
        ph_now = get_ph_time()
        start_str = request.args.get('start')
        end_str   = request.args.get('end')
        if start_str and end_str:
            try:
                start_date = datetime.strptime(start_str, '%Y-%m-%d').date()
                end_date   = datetime.strptime(end_str,   '%Y-%m-%d').date()
            except ValueError:
                return jsonify({"error": "Invalid date format"}), 400
        else:
            days = int(request.args.get('days', 7))
            days = min(max(days, 1), 90)
            end_date   = ph_now.date()
            start_date = end_date - timedelta(days=days - 1)
        result = []
        current = start_date
        while current <= end_date:
            day_start = datetime(current.year, current.month, current.day, 0, 0, 0)
            day_end   = datetime(current.year, current.month, current.day, 23, 59, 59)
            orders = Reservation.query.filter(
                Reservation.created_at >= day_start,
                Reservation.created_at <= day_end,
                Reservation.status == 'Completed'
            ).all()
            total = sum(o.total_investment or 0.0 for o in orders)
            result.append({
                "date": current.strftime('%b %d'),
                "revenue": round(total, 2),
                "orders": len(orders)
            })
            current += timedelta(days=1)
        return jsonify(result)
    except Exception as e:
        print(f"analytics_sales_trend error: {e}")
        return jsonify({"error": str(e)}), 500

@app.route('/api/admin/analytics/top_items', methods=['GET'])
def analytics_top_items():
    if not session.get('is_admin'):
        return jsonify({"error": "Unauthorized"}), 403
    ph_now = get_ph_time()
    start_str = request.args.get('start')
    end_str   = request.args.get('end')
    if start_str and end_str:
        try:
            start_date = datetime.strptime(start_str, '%Y-%m-%d').date()
            end_date   = datetime.strptime(end_str,   '%Y-%m-%d').date()
        except ValueError:
            return jsonify({"error": "Invalid date format"}), 400
        cutoff_start = datetime(start_date.year, start_date.month, start_date.day, 0, 0, 0)
        cutoff_end   = datetime(end_date.year, end_date.month, end_date.day, 23, 59, 59)
        completed = Reservation.query.filter(
            Reservation.created_at >= cutoff_start,
            Reservation.created_at <= cutoff_end,
            Reservation.status == 'Completed'
        ).all()
    else:
        days = int(request.args.get('days', 30))
        days = min(max(days, 1), 90)
        cutoff = ph_now - timedelta(days=days)
        completed = Reservation.query.filter(
            Reservation.created_at >= cutoff,
            Reservation.status == 'Completed'
        ).all()
    item_counts = {}
    for r in completed:
        for inf in r.infusions:
            n = inf.foundation
            if n not in item_counts:
                item_counts[n] = {"name": n, "count": 0, "revenue": 0.0}
            item_counts[n]["count"] += 1
            item_counts[n]["revenue"] += round(inf.item_total, 2)
    top = sorted(item_counts.values(), key=lambda x: x["count"], reverse=True)[:10]
    return jsonify(top)

@app.route('/api/admin/analytics/hourly', methods=['GET'])
def analytics_hourly():
    if not session.get('is_admin'):
        return jsonify({"error": "Unauthorized"}), 403
    try:
        ph_now = get_ph_time()
        day_start = ph_now.replace(hour=0, minute=0, second=0, microsecond=0)
        orders = Reservation.query.filter(
            Reservation.created_at >= day_start,
            Reservation.status.in_(['Completed','Ready for Pick-up','Preparing Order'])
        ).all()
        hourly = {h: 0 for h in range(24)}
        for o in orders:
            if o.created_at is not None:
                hourly[o.created_at.hour] += 1
        return jsonify([{"hour": f"{h}:00", "orders": c} for h, c in hourly.items()])
    except Exception as e:
        print(f"analytics_hourly error: {e}")
        return jsonify({"error": str(e)}), 500

def _initialize_db():
    """Run DB creation + seeding inside an app context.
    Called once at module load (local/Render) and also lazily on first request
    on Vercel so a startup crash does not produce a blank 500."""
    try:
        db.create_all()
    except Exception as _e:
        print(f"db.create_all() skipped: {_e}")
    # Belt-and-suspenders: explicitly create any tables that may be missing
    # in an existing database that predates these models being added.
    _critical = [
        ("order_meta", "CREATE TABLE IF NOT EXISTS order_meta (id INTEGER PRIMARY KEY AUTOINCREMENT, reservation_id INTEGER NOT NULL UNIQUE REFERENCES reservations(id), is_flagged BOOLEAN NOT NULL DEFAULT 0, flag_reason VARCHAR(300) DEFAULT \'\', requires_staff_confirmation BOOLEAN NOT NULL DEFAULT 0, staff_confirmed BOOLEAN NOT NULL DEFAULT 0, prepayment_required BOOLEAN NOT NULL DEFAULT 0, prepayment_amount FLOAT DEFAULT 0.0, prepayment_collected BOOLEAN NOT NULL DEFAULT 0, has_pickup_photo BOOLEAN NOT NULL DEFAULT 0, prev_status VARCHAR(50) DEFAULT \'\', created_at DATETIME)"),
        ("blacklisted_ips", "CREATE TABLE IF NOT EXISTS blacklisted_ips (id INTEGER PRIMARY KEY AUTOINCREMENT, ip_address VARCHAR(60) NOT NULL UNIQUE, reason VARCHAR(300) DEFAULT \'\', is_manual BOOLEAN DEFAULT 0, created_at DATETIME)"),
        ("failed_login_attempts", "CREATE TABLE IF NOT EXISTS failed_login_attempts (id INTEGER PRIMARY KEY AUTOINCREMENT, ip_address VARCHAR(60) NOT NULL, attempt_type VARCHAR(20) DEFAULT \'admin\', user_agent VARCHAR(300) DEFAULT \'\', created_at DATETIME)"),
        ("staff_announcements", "CREATE TABLE IF NOT EXISTS staff_announcements (id INTEGER PRIMARY KEY AUTOINCREMENT, title VARCHAR(120) NOT NULL, message TEXT NOT NULL, priority VARCHAR(20) DEFAULT \'normal\', is_active BOOLEAN DEFAULT 1, created_at DATETIME)"),
        ("waste_logs", "CREATE TABLE IF NOT EXISTS waste_logs (id INTEGER PRIMARY KEY AUTOINCREMENT, ingredient_name VARCHAR(100) NOT NULL, quantity FLOAT NOT NULL, unit VARCHAR(20) DEFAULT \'units\', reason VARCHAR(200) DEFAULT \'\', logged_by VARCHAR(50) DEFAULT \'Employee\', created_at DATETIME)"),
        ("customer_blocklist", "CREATE TABLE IF NOT EXISTS customer_blocklist (id INTEGER PRIMARY KEY AUTOINCREMENT, block_type VARCHAR(20) NOT NULL, value VARCHAR(200) NOT NULL, reason VARCHAR(300) DEFAULT \'\', added_by VARCHAR(50) DEFAULT \'Admin\', created_at DATETIME)"),
        ("customer_reputations", "CREATE TABLE IF NOT EXISTS customer_reputations (id INTEGER PRIMARY KEY AUTOINCREMENT, identifier VARCHAR(200) NOT NULL UNIQUE, display_name VARCHAR(120) DEFAULT \'\', total_orders INTEGER DEFAULT 0, noshow_count INTEGER DEFAULT 0, completed_count INTEGER DEFAULT 0, is_watchlist BOOLEAN DEFAULT 0, requires_prepayment BOOLEAN DEFAULT 0, is_blocked BOOLEAN DEFAULT 0, notes VARCHAR(500) DEFAULT \'\', created_at DATETIME)"),
        ("promo_codes", "CREATE TABLE IF NOT EXISTS promo_codes (id INTEGER PRIMARY KEY AUTOINCREMENT, code VARCHAR(30) NOT NULL UNIQUE, description VARCHAR(200) DEFAULT \'\', discount_type VARCHAR(20) DEFAULT \'percent\', discount_value FLOAT NOT NULL DEFAULT 0.0, min_order FLOAT NOT NULL DEFAULT 0.0, max_uses INTEGER, used_count INTEGER DEFAULT 0, is_active BOOLEAN DEFAULT 1, expires_at DATETIME, created_at DATETIME)"),
        ("item_availability_queries", "CREATE TABLE IF NOT EXISTS item_availability_queries (id INTEGER PRIMARY KEY AUTOINCREMENT, reservation_id INTEGER NOT NULL REFERENCES reservations(id), order_code VARCHAR(20) NOT NULL, unavailable_items TEXT DEFAULT \'[]\', reason VARCHAR(100) DEFAULT \'Out of Stock\', customer_decision VARCHAR(20), created_at DATETIME)"),
        ("quick_checklists", "CREATE TABLE IF NOT EXISTS quick_checklists (id INTEGER PRIMARY KEY AUTOINCREMENT, task_name VARCHAR(150) NOT NULL, checklist_type VARCHAR(20) DEFAULT \'opening\', is_active BOOLEAN DEFAULT 1, display_order INTEGER DEFAULT 0, created_at DATETIME)"),
        ("order_pickup_photos", "CREATE TABLE IF NOT EXISTS order_pickup_photos (id INTEGER PRIMARY KEY AUTOINCREMENT, reservation_id INTEGER NOT NULL REFERENCES reservations(id), photo_data TEXT NOT NULL, taken_by VARCHAR(50) DEFAULT \'Staff\', created_at DATETIME)"),
    ]
    for _tname, _ddl in _critical:
        try:
            db.session.execute(db.text(_ddl))
            db.session.commit()
        except Exception:
            db.session.rollback()

# ── Schema-guard: runs before every request until schema is verified ─────────
# On Vercel/serverless the module reloads on cold-starts; startup migrations can
# fail silently against an existing Postgres DB that has stale schema.
# This guard proactively ensures every critical column exists before any route
# handler runs, so 500s caused by "column does not exist" are self-healing.
_schema_ok = False   # flips True once every column is confirmed present

def _ensure_schema():
    """Add any missing columns to the live DB.  Safe to call repeatedly."""
    global _schema_ok
    if _schema_ok:
        return
    try:
        db.create_all()   # creates completely missing tables (idempotent)
    except Exception as e:
        print(f"_ensure_schema: db.create_all() warning: {e}")

    is_pg = 'postgresql' in str(db.engine.url)

    def _col_exists(table, col):
        try:
            if is_pg:
                return db.session.execute(db.text(
                    "SELECT COUNT(*) FROM information_schema.columns "
                    f"WHERE table_name=:t AND column_name=:c"
                ), {"t": table, "c": col}).scalar() > 0
            else:
                rows = db.session.execute(db.text(f"PRAGMA table_info({table})")).fetchall()
                return any(r[1] == col for r in rows)
        except Exception:
            return False

    def _add_col(table, col, defn_sqlite, defn_pg=None):
        if _col_exists(table, col):
            return True   # already there
        defn = (defn_pg or defn_sqlite) if is_pg else defn_sqlite
        try:
            db.session.execute(db.text(f"ALTER TABLE {table} ADD COLUMN {col} {defn}"))
            db.session.commit()
            print(f"_ensure_schema: added {table}.{col}")
            return True
        except Exception as e:
            db.session.rollback()
            print(f"_ensure_schema: could not add {table}.{col}: {e}")
            return False

    # reservations – columns added after initial release
    all_ok = True
    all_ok &= _add_col("reservations", "cancel_reason",  "VARCHAR(300) DEFAULT ''")
    all_ok &= _add_col("reservations", "patron_address", "VARCHAR(300) DEFAULT ''")
    all_ok &= _add_col("reservations", "order_source",   "VARCHAR(30)  DEFAULT 'Online'")
    all_ok &= _add_col("reservations", "patron_phone",   "VARCHAR(30)  DEFAULT ''")
    all_ok &= _add_col("reservations", "is_paid",
                        "BOOLEAN NOT NULL DEFAULT 0",
                        "BOOLEAN NOT NULL DEFAULT FALSE")
    # menu_items
    all_ok &= _add_col("menu_items", "is_out_of_stock",
                        "BOOLEAN NOT NULL DEFAULT 0",
                        "BOOLEAN NOT NULL DEFAULT FALSE")
    # customer_logs
    all_ok &= _add_col("customer_logs", "items",       "TEXT        NOT NULL DEFAULT ''")
    all_ok &= _add_col("customer_logs", "pickup_time", "VARCHAR(50) NOT NULL DEFAULT ''")
    all_ok &= _add_col("customer_logs", "phone",       "VARCHAR(30) NOT NULL DEFAULT ''")
    all_ok &= _add_col("customer_logs", "user_agent",  "VARCHAR(300) DEFAULT ''")
    all_ok &= _add_col("customer_logs", "ip_address",  "VARCHAR(60)  DEFAULT ''")
    # reservations – device tracking columns
    all_ok &= _add_col("reservations",  "user_agent",  "VARCHAR(300) DEFAULT ''")
    all_ok &= _add_col("reservations",  "ip_address",  "VARCHAR(60)  DEFAULT ''")

    # order_ratings table
    try:
        db.session.execute(db.text("""
            CREATE TABLE IF NOT EXISTS order_ratings (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                reservation_id INTEGER NOT NULL UNIQUE REFERENCES reservations(id),
                order_code VARCHAR(20) NOT NULL,
                customer_email VARCHAR(120) NOT NULL,
                stars INTEGER NOT NULL,
                feedback TEXT DEFAULT '',
                created_at DATETIME
            )
        """))
        db.session.commit()
    except Exception:
        db.session.rollback()

    if all_ok:
        _schema_ok = True   # stop checking once every column is confirmed


_db_initialized = False

@app.before_request
def _lazy_db_init():
    global _db_initialized
    _ensure_schema()          # self-healing schema guard (fast no-op once schema is ok)
    if not _db_initialized:
        try:
            _initialize_db()
            _db_initialized = True
        except Exception as _init_err:
            print(f"_lazy_db_init error (will retry): {_init_err}")

