@app.route('/api/rating/check', methods=['GET'])
def rating_check():
    """Check if the customer has already submitted a rating for a given order code."""
    code = request.args.get('code', '').strip()
    if not code:
        return jsonify({"eligible": False, "reason": "no_code"})
    try:
        order = Reservation.query.filter_by(reservation_code=code).first()
        if not order:
            return jsonify({"eligible": False, "reason": "not_found"})
        if order.status != 'Completed':
            return jsonify({"eligible": False, "reason": "not_completed"})
        existing = OrderRating.query.filter_by(reservation_id=order.id).first()
        if existing:
            return jsonify({"eligible": False, "reason": "already_rated"})
        # Check if this is their first-ever completed order (by email)
        prev_completed = Reservation.query.filter(
            Reservation.patron_email == order.patron_email,
            Reservation.status == 'Completed',
            Reservation.id != order.id
        ).first()
        return jsonify({
            "eligible": True,
            "order_id": order.id,
            "is_first_order": prev_completed is None
        })
    except Exception as e:
        return jsonify({"eligible": False, "reason": str(e)})


@app.route('/api/rating/submit', methods=['POST'])
def rating_submit():
    """Accept a one-time rating + feedback from the customer."""
    data = request.get_json(silent=True) or {}
    code  = (data.get('code') or '').strip()
    stars = int(data.get('stars', 0))
    feedback = (data.get('feedback') or '').strip()[:1000]

    if not code or not (1 <= stars <= 5):
        return jsonify({"error": "Invalid data"}), 400

    try:
        order = Reservation.query.filter_by(reservation_code=code).first()
        if not order:
            return jsonify({"error": "Order not found"}), 404
        if order.status != 'Completed':
            return jsonify({"error": "Order not completed yet"}), 400
        if OrderRating.query.filter_by(reservation_id=order.id).first():
            return jsonify({"error": "Already rated"}), 409

        rating = OrderRating(
            reservation_id=order.id,
            order_code=code,
            customer_email=order.patron_email,
            stars=stars,
            feedback=feedback
        )
        db.session.add(rating)
        db.session.commit()
        log_audit("Customer Rating", f"Order {code} rated {stars}★" + (f" — {feedback[:60]}" if feedback else ""))
        return jsonify({"status": "success"})
    except Exception as e:
        db.session.rollback()
        return jsonify({"error": str(e)}), 500


@app.route('/api/rating/summary', methods=['GET'])
def rating_summary():
    """Return all ratings for the admin dashboard."""
    if not session.get('is_admin'):
        return jsonify({"error": "Unauthorized"}), 403
    try:
        ratings = OrderRating.query.order_by(OrderRating.created_at.desc()).limit(100).all()
        total = len(ratings)
        avg = round(sum(r.stars for r in ratings) / total, 2) if total else 0
        dist = {str(i): sum(1 for r in ratings if r.stars == i) for i in range(1, 6)}
        return jsonify({
            "average": avg,
            "total": total,
            "distribution": dist,
            "recent": [{
                "code": r.order_code,
                "stars": r.stars,
                "feedback": r.feedback or '',
                "date": r.created_at.strftime('%b %d, %Y') if r.created_at else ''
            } for r in ratings[:20]]
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 500


@app.route('/api/dev/customers', methods=['GET'])
@_dev_auth_required
def dev_customers():
    """Returns recent orders with device info for the Dev Portal customer tracker."""
    try:
        limit = min(int(request.args.get('limit', 30)), 100)
        orders = Reservation.query.order_by(Reservation.created_at.desc()).limit(limit).all()
        result = []
        for o in orders:
            ua = (o.user_agent or '').strip()
            device = parse_user_agent(ua)
            result.append({
                "id": o.id,
                "code": o.reservation_code,
                "name": o.patron_name or '—',
                "source": o.order_source or 'Online',
                "status": o.status or '',
                "ip": o.ip_address or '—',
                "ua": ua,
                "device": device,
                "total": o.total_investment or 0.0,
                "created_at": o.created_at.strftime('%b %d %H:%M') if o.created_at else '—'
            })
        return jsonify(result)
    except Exception as e:
        return jsonify({"error": str(e)}), 500


def parse_user_agent(ua):
    """Convert raw UA string into a human-readable device label."""
    if not ua:
        return '—'
    # OS detection
    if 'iPhone' in ua:
        os = 'iPhone'
    elif 'iPad' in ua:
        os = 'iPad'
    elif 'Android' in ua:
        # Try to extract device model e.g. "SM-G991B" or "Pixel 6"
        import re
        m = re.search(r'Android [0-9.]+; ([^)]+)', ua)
        os = m.group(1).strip() if m else 'Android'
    elif 'Windows NT' in ua:
        ver_map = {'10.0':'10/11','6.3':'8.1','6.2':'8','6.1':'7','6.0':'Vista'}
        m2 = re.search(r'Windows NT ([0-9.]+)', ua) if True else None
        import re
        m2 = re.search(r'Windows NT ([0-9.]+)', ua)
        os = 'Windows ' + ver_map.get(m2.group(1) if m2 else '', m2.group(1) if m2 else '') if m2 else 'Windows'
    elif 'Macintosh' in ua or 'Mac OS X' in ua:
        os = 'Mac'
    elif 'Linux' in ua:
        os = 'Linux'
    elif 'CrOS' in ua:
        os = 'ChromeOS'
    else:
        os = ''
    # Browser detection
    import re
    if 'SamsungBrowser' in ua:
        browser = 'Samsung Browser'
    elif 'EdgA' in ua or 'EdgiOS' in ua or 'Edg/' in ua:
        browser = 'Edge'
    elif 'OPR/' in ua or 'OPiOS' in ua:
        browser = 'Opera'
    elif 'YaBrowser' in ua:
        browser = 'Yandex'
    elif 'UCBrowser' in ua:
        browser = 'UC Browser'
    elif 'FBAN' in ua or 'FBAV' in ua:
        browser = 'Facebook App'
    elif 'Instagram' in ua:
        browser = 'Instagram App'
    elif 'CriOS' in ua:
        browser = 'Chrome (iOS)'
    elif 'FxiOS' in ua:
        browser = 'Firefox (iOS)'
    elif 'Chrome' in ua:
        m3 = re.search(r'Chrome/([0-9]+)', ua)
        browser = f"Chrome {m3.group(1)}" if m3 else 'Chrome'
    elif 'Firefox' in ua:
        browser = 'Firefox'
    elif 'Safari' in ua:
        browser = 'Safari'
    else:
        browser = ''
    parts = [x for x in [browser, os] if x]
    return ' · '.join(parts) if parts else ua[:50]


@app.route('/api/dev/force_migrate', methods=['POST'])
@_dev_auth_required
def dev_force_migrate():
    """Force-run all column migrations. Call this once after deploying to fix missing columns."""
    results = []
    is_pg = 'postgresql' in str(db.engine.url)

    def col_exists(table, col):
        try:
            if is_pg:
                r = db.session.execute(db.text(
                    "SELECT COUNT(*) FROM information_schema.columns "
                    f"WHERE table_name='{table}' AND column_name='{col}'"
                )).scalar()
                return r > 0
            else:
                rows = db.session.execute(db.text(f"PRAGMA table_info({table})")).fetchall()
                return any(row[1] == col for row in rows)
        except Exception as e:
            return False

    def run_alter(table, col, col_def_sqlite, col_def_pg=None):
        if col_exists(table, col):
            results.append({"col": f"{table}.{col}", "status": "already_exists"})
            return
        col_def = (col_def_pg or col_def_sqlite) if is_pg else col_def_sqlite
        try:
            db.session.execute(db.text(f"ALTER TABLE {table} ADD COLUMN {col} {col_def}"))
            db.session.commit()
            results.append({"col": f"{table}.{col}", "status": "added"})
        except Exception as e:
            db.session.rollback()
            results.append({"col": f"{table}.{col}", "status": "error", "msg": str(e)})

    # reservations columns
    run_alter("reservations", "cancel_reason", "VARCHAR(300) DEFAULT ''")
    run_alter("reservations", "patron_address", "VARCHAR(300) DEFAULT ''")
    run_alter("reservations", "order_source", "VARCHAR(30) DEFAULT 'Online'")
    run_alter("reservations", "patron_phone", "VARCHAR(30) DEFAULT ''")
    run_alter("reservations", "is_paid",
              "BOOLEAN NOT NULL DEFAULT 0",
              "BOOLEAN NOT NULL DEFAULT FALSE")

    # menu_items columns
    run_alter("menu_items", "is_out_of_stock",
              "BOOLEAN NOT NULL DEFAULT 0",
              "BOOLEAN NOT NULL DEFAULT FALSE")

    # customer_logs columns
    run_alter("customer_logs", "items", "TEXT NOT NULL DEFAULT ''")
    run_alter("customer_logs", "pickup_time", "VARCHAR(50) NOT NULL DEFAULT ''")
    run_alter("customer_logs", "phone", "VARCHAR(30) NOT NULL DEFAULT ''")

    # Also run create_all for any missing tables
    try:
        db.create_all()
        results.append({"col": "db.create_all()", "status": "ok"})
    except Exception as e:
        results.append({"col": "db.create_all()", "status": "error", "msg": str(e)})

    log_audit("Dev: Force Migrate", f"Ran force_migrate: {len(results)} operations")
    return jsonify({"results": results})


@app.route('/api/dev/env')
@_dev_auth_required
def dev_env():
    def mask(val):
        if not val: return None
        if len(val) <= 4: return '****'
        return val[:2] + '*' * (len(val) - 4) + val[-2:]
    checks = [
        ("DATABASE_URL", os.environ.get('DATABASE_URL')),
        ("SECRET_KEY", os.environ.get('SECRET_KEY')),
        ("ADMIN_PIN", os.environ.get('ADMIN_PIN')),
        ("DEV_KEY", os.environ.get('DEV_KEY')),
        ("GOOGLE_CLIENT_ID", os.environ.get('GOOGLE_CLIENT_ID')),
        ("VERCEL", os.environ.get('VERCEL') or os.environ.get('VERCEL_ENV')),
        ("RENDER", os.environ.get('RENDER')),
        ("DYNO", os.environ.get('DYNO')),
    ]
    result = []
    for key, val in checks:
        if val:
            result.append({"key": key, "value": mask(val), "set": True})
        else:
            result.append({"key": key, "value": "NOT SET", "set": False})
    result.append({"key": "DB_ENGINE", "value": app.config['SQLALCHEMY_DATABASE_URI'].split(':')[0], "set": True})
    result.append({"key": "ON_CLOUD", "value": str(_ON_CLOUD), "set": _ON_CLOUD})
    return jsonify(result)


# ==========================================
# 11. APPLICATION RUNNER
# ==========================================

if __name__ == '__main__':
    if os.environ.get('RENDER') or os.environ.get('DYNO'):
        port = int(os.environ.get('PORT', 5000))
        app.run(host='0.0.0.0', port=port)
    else:
        import webbrowser
        from threading import Timer

        def open_browser():
            url = 'http://127.0.0.1:5000/login'
            # Try Chrome first; fall back to default browser
            opened = False
            for chrome_name in ('chrome', 'google-chrome', 'google-chrome-stable', 'chromium', 'chromium-browser'):
                try:
                    chrome = webbrowser.get(chrome_name)
                    chrome.open_new(url)
                    opened = True
                    break
                except Exception:
                    continue
            if not opened:
                # Windows: try registry path directly
                import subprocess, sys
                if sys.platform == 'win32':
                    try:
                        subprocess.Popen([r'C:\Program Files\Google\Chrome\Application\chrome.exe', url])
                        opened = True
                    except Exception:
                        pass
                if not opened:
                    webbrowser.open_new(url)  # final fallback

        print("==================================================")
        print(" STARTING SYSTEM (DESKTOP APP MODE)")
        print(f" CUSTOMER POS LINK: http://{get_local_ip()}:5000/")
        print(" ADMIN DASHBOARD:   http://127.0.0.1:5000/login")
        print("==================================================")
        
        Timer(1.5, open_browser).start()
        app.run(host='0.0.0.0', port=5000, debug=False, use_reloader=True)
